1	export type Cell = [number, number];
2	
3	const SURVIVAL_MIN_NEIGHBORS = 2;
4	const SURVIVAL_MAX_NEIGHBORS = 3;
5	
6	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
7	  [-1, -1], [-1, 0], [-1, 1],
8	  [0, -1],           [0, 1],
9	  [1, -1],  [1, 0],  [1, 1],
10	];
11	
12	function cellKey(x: number, y: number): string {
13	  return `${x},${y}`;
14	}
15	
16	function countLiveNeighbors(x: number, y: number, liveSet: Set<string>): number {
17	  return NEIGHBOR_OFFSETS.reduce(
18	    (count, [dx, dy]) => count + (liveSet.has(cellKey(x + dx, y + dy)) ? 1 : 0),
19	    0,
20	  );
21	}
22	
23	function survives(neighborCount: number): boolean {
24	  return neighborCount === SURVIVAL_MIN_NEIGHBORS || neighborCount === SURVIVAL_MAX_NEIGHBORS;
25	}
26	
27	export function nextGeneration(cells: Cell[]): Cell[] {
28	  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
29	  return cells.filter(([x, y]) => survives(countLiveNeighbors(x, y, liveSet)));
30	}
